 1	import React, { FC } from 'react';
 2	
 3	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import {
 5	  convertYAMLUserDataObject,
 6	  getCloudInitData,
 7	  getCloudInitVolume,
 8	} from '@kubevirt-utils/components/CloudinitModal/utils/cloudinit-utils';
 9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
10	import { NO_DATA_DASH } from '@kubevirt-utils/resources/vm/utils/constants';
11	import { DescriptionList, Stack, StackItem } from '@patternfly/react-core';
12	
13	import VirtualMachineDescriptionItem from '../VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
14	
15	import CloudInitInfoHelper from './CloudinitInfoHelper';
16	
17	export const CloudInitDescription: FC<{ vm: V1VirtualMachine }> = ({ vm }) => {
18	  const { t } = useKubevirtTranslation();
19	  const cloudInitData = getCloudInitData(getCloudInitVolume(vm));
20	  const userData = convertYAMLUserDataObject(cloudInitData?.userData);
21	
22	  return (
23	    <Stack hasGutter>
24	      <StackItem>
25	        <CloudInitInfoHelper />
26	      </StackItem>
27	      <StackItem>
28	        <DescriptionList
29	          className="pf-v6-c-description-list"
30	          columnModifier={{ lg: '1Col', xl: '3Col' }}
31	          isCompact
32	        >
33	          <VirtualMachineDescriptionItem
34	            descriptionData={userData?.user || NO_DATA_DASH}
35	            descriptionHeader={t('User')}
36	          />
37	          <VirtualMachineDescriptionItem
38	            descriptionData={userData?.password?.toString().replace(/./g, '*') || NO_DATA_DASH}
39	            descriptionHeader={t('Password')}
40	          />
41	          <VirtualMachineDescriptionItem
42	            descriptionData={cloudInitData?.networkData ? t('Custom') : t('Default')}
43	            descriptionHeader={t('Network data')}
44	          />
45	        </DescriptionList>
46	      </StackItem>
47	    </Stack>
48	  );
49	};

